import time
import anthropic
from dataclasses import dataclass, field

client = anthropic.Anthropic()

@dataclass
class ModelHealth:
    """Tracks failure count and circuit state for one model."""
    failures: int = 0
    open_until: float = 0.0
    failure_threshold: int = 5
    recovery_window: float = 60.0

    def is_open(self) -> bool:
        if self.open_until == 0:
            return False
        if time.time() > self.open_until:
            # Enter HALF-OPEN: allow one probe attempt
            self.open_until = 0
            self.failures = 0
            return False
        return True

    def record_failure(self):
        self.failures += 1
        if self.failures >= self.failure_threshold:
            self.open_until = time.time() + self.recovery_window
            print(f"[circuit] OPEN for {self.recovery_window} s")

    def record_success(self):
        self.failures = 0
        self.open_until = 0


MODEL_CHAIN = ["claude-opus-4-5", "claude-sonnet-4-5", "claude-haiku-4-5"]
health: dict[str, ModelHealth] = {m: ModelHealth() for m in MODEL_CHAIN}


def call_with_circuit_breaker(messages: list[dict]) -> str:
    for model in MODEL_CHAIN:
        state = health[model]
        if state.is_open():
            print(f"[circuit] Skipping {model} — circuit OPEN")
            continue
        try:
            resp = client.messages.create(
                model=model,
                max_tokens=512,
                messages=messages,
            )
            state.record_success()
            return resp.content[0].text
        except (anthropic.RateLimitError, anthropic.APIStatusError) as e:
            state.record_failure()
            print(f"[circuit] {model} failed ({e}), moving to next")

    raise RuntimeError("All models unavailable")

import anthropic
import time
from dataclasses import dataclass

client = anthropic.Anthropic()

SYNTHESIS_CHAIN = ["claude-opus-4-5", "claude-sonnet-4-5"]
EXTRACTION_CHAIN = ["claude-haiku-4-5", "claude-sonnet-4-5"]

@dataclass
class ModelHealth:
    failures: int = 0
    open_until: float = 0.0
    threshold: int = 5
    cooldown: float = 120.0

    def available(self) -> bool:
        if self.open_until and time.time() < self.open_until:
            return False
        if self.open_until:
            self.open_until = 0.0
            self.failures = 0
        return True

    def fail(self):
        self.failures += 1
        if self.failures >= self.threshold:
            self.open_until = time.time() + self.cooldown

    def ok(self):
        self.failures = 0


_health: dict[str, ModelHealth] = {}

def get_health(model: str) -> ModelHealth:
    if model not in _health:
        _health[model] = ModelHealth()
    return _health[model]


def llm_call(chain: list[str], prompt: str, max_tokens: int = 1024) -> str:
    for model in chain:
        h = get_health(model)
        if not h.available():
            continue
        try:
            resp = client.messages.create(
                model=model,
                max_tokens=max_tokens,
                messages=[{"role": "user", "content": prompt}],
            )
            h.ok()
            return resp.content[0].text
        except (anthropic.RateLimitError, anthropic.APIStatusError) as e:
            h.fail()
            print(f"[fallback] {model} failed ({type(e).__name__}), trying next")
    raise RuntimeError(f"No model available in chain: {chain}")


def process_research_batch(urls: list[str]) -> str:
    facts = []
    for url in urls:
        fact = llm_call(
            EXTRACTION_CHAIN,
            f"Extract 3 key facts from this URL content: {url}",
            max_tokens=256,
        )
        facts.append(fact)

    synthesis = llm_call(
        SYNTHESIS_CHAIN,
        "Synthesise the following facts into a concise report:\n" + "\n".join(facts),
        max_tokens=2048,
    )
    return synthesis


report = process_research_batch([
    "https://example.com/article-1",
    "https://example.com/article-2",
])
print(report)
